@interface WBCustomPopupManager()

@property(strong, nonatomic) UIViewController *currentViewController;
@property(assign, nonatomic) WBNoticeStyle popupStyle;
@property(copy, nonatomic) NSString *mainImageRichMessageLinkId;
@property(copy, nonatomic) NSString *richMessageNoticeName;
@property(copy, nonatomic) NSString *mainImageRichMessageLinkLabel;
@property(copy, nonatomic) NSArray *buttonData;

