        self.notice = notice;
        self.delegate = self;
    }
    return self;
}

- (void)dismissViewControllerAnimated:(BOOL)flag completion:(void (^)(void))completion {
    BOOL immediatelyDismiss = [self checkIfShouldDismissImmediately];
    if (immediatelyDismiss) {
        [super dismissViewControllerAnimated:flag completion:completion];
        return;
    }
    self.childViewControllers.firstObject.view.alpha = 0;
    self.shouldDismissOnAppear = true;
    self.dismissAnimationFlag = flag;
    self.dismissCompletionBlock = completion;
}

- (BOOL)checkIfShouldDismissImmediately {
    return [self.childViewControllers count] == 1;
}

#pragma mark - <UINavigationControllerDelegate>

- (id<UIViewControllerAnimatedTransitioning>)navigationController:(UINavigationController *)navigationController animationControllerForOperation:(UINavigationControllerOperation)operation fromViewController:(UIViewController *)fromVC toViewController:(UIViewController *)toVC {
    if (operation != UINavigationControllerOperationPop) return nil;
    if (toVC == self.childViewControllers[0] && self.shouldDismissOnAppear) {
        [super dismissViewControllerAnimated:self.dismissAnimationFlag completion:self.dismissCompletionBlock];
    }
    return nil;
}

