    WBPopUpAlertController *popupVC = [self alertControllerWithTitle:notice.title message:notice.content preferredStyle:UIAlertControllerStyleAlert];
    for (WBRichMessageLinkModel *op in notice.operations) {
        UIAlertActionStyle style = 0;
        if (op.style == WBRichMessageLinkStylePrimary) {
            style = UIAlertActionStyleDefault;
        } else if (op.style == WBRichMessageLinkStyleNormal) {
            style = UIAlertActionStyleCancel;
        } else if (op.style == WBRichMessageLinkStyleGrey) {
            style = UIAlertActionStyleDestructive;
        }
        UIAlertAction *action = [UIAlertAction actionWithTitle:op.label style:style handler:nil];
        [popupVC addAction:action];
    }
    if (popupVC) {
        popupVC.notice = notice;
    }
    return popupVC;
}

