- (void)setUpNativeAlertActionViewWithOperation:(WBRichMessageLinkModel *)operation index:(int)index {
    UILabel *actionLabel = [self getActionLabelWithOperaton:operation];
    UIView *actionView = [self getActionViewWithActionLabel:actionLabel];
    UIButton *transparentButton = [UIButton buttonWithType:UIButtonTypeCustom];
//        transparentButton.backgroundColor = [UIColor grayColor];
//        [transparentButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
//        [transparentButton setTitle:op.label forState:UIControlStateNormal];
    transparentButton.tag = index;
    [transparentButton addTarget:self action:@selector(buttonClicked:) forControlEvents:UIControlEventTouchUpInside];
    [self.view addSubview:transparentButton];
    [transparentButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(actionView);
    }];
    if (operation.timeout) {
        transparentButton.userInteractionEnabled = false;
        NSTimer *timer = [NSTimer scheduledTimerWithTimeInterval:1.0 block:^(NSTimer * _Nonnull timer) {
            if (operation.timeout) {
                NSString *title = [operation.label stringByAppendingFormat:@"  (%d)", operation.timeout];
                actionLabel.text = title;
                operation.timeout--;
            } else {
                actionLabel.text = operation.label;
                [timer invalidate];
                transparentButton.userInteractionEnabled = true;
            }
        } repeats:true];
        [timer fire];
    }
}

