- (UILabel *)getActionLabelWithOperaton:(WBRichMessageLinkModel *)op inView:(UIView *)view {
    if ([view isKindOfClass:[UILabel class]] && [[((UILabel *)view) text] isEqualToString:op.label]) return (UILabel *)view;
    for (UIView *subview in view.subviews) {
        UILabel *res = [self getActionLabelWithOperaton:op inView:subview];
        if (res) return res;
    }
    return nil;
}

