                make.top.equalTo(self.imageView.mas_bottom).offset(IMAGE_BOTTOM_PADDING);
            } else {
                make.top.equalTo(mainView).offset(POPUP_TOP_PADDING);
            }
        }
        make.centerX.equalTo(mainView);
        make.left.equalTo(mainView).offset(SUBTITLE_LEFT_RIGHT_PADDING);
    }];
    UIButton *prevButton = nil;
    for(UIButton *button in self.buttons) {
        [mainView addSubview:button];
        [button mas_makeConstraints:^(MASConstraintMaker *make) {
            if (!prevButton) {
                if (self.subTitleLabel.text.length) {
                    make.top.equalTo(self.subTitleLabel.mas_bottom).offset(SUBTITLE_BOTTOM_PADDING);
                } else {
                    if (self.titleLabel.text.length) {
                        make.top.equalTo(self.titleLabel.mas_bottom).offset(TITLE_BOTTOM_PADDING);
                    } else {
                        if (self.imageView) {
                            make.top.equalTo(self.imageView.mas_bottom).offset(IMAGE_BOTTOM_PADDING);
                        } else {
                            make.top.equalTo(mainView).offset(POPUP_TOP_PADDING);
                        }
                    }
                }
            } else {
                make.top.equalTo(prevButton.mas_bottom).offset(BUTTON_PADDING);
            }
            make.height.mas_equalTo(BUTTON_HEIGHT);
            make.width.mas_equalTo(BUTTON_WIDTH);
            make.centerX.mas_equalTo(mainView);
        }];
        prevButton = button;
    }

    [mainView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.width.mas_equalTo(POPUP_WIDTH);
        if (prevButton) {
            make.bottom.equalTo(self.buttons.lastObject).offset(POPUP_BOTTOM_PADDING);
        } else {
            if (self.subTitleLabel.text.length) {
                make.bottom.equalTo(self.subTitleLabel).offset(POPUP_BOTTOM_PADDING);
            } else {
                if (self.titleLabel.text.length) {
                    make.bottom.equalTo(self.titleLabel).offset(POPUP_BOTTOM_PADDING);
                } else {
                    if (self.imageView) {
                        make.bottom.equalTo(self.imageView);
                    } else {
                        make.height.mas_equalTo(EMPTY_IMAGE_PADDING);
                    }
                }
            }
        }
        make.centerX.equalTo(self.view);
        make.centerY.equalTo(self.view).offset(ZOOM(-30));
    }];
}

