- (UIButton *)newPrimaryButton:(WBRichMessageLinkModel *)operation {
    UIButton *button = [self newCommonButton:operation];
    if (!operation.timeout) {
        button.backgroundColor = GreenColor_g;
        [button setTitleColor:UIColor.whiteColor forState:UIControlStateNormal];
    } else {
        [button setTitleColor:WBColorHex(0x999999) forState:UIControlStateNormal];
    }
    return button;
}

- (UIButton *)newNormalButton:(WBRichMessageLinkModel *)operation {
    UIButton *button = [self newCommonButton:operation];
    button.layer.borderColor = WBColorHex(0xEEEEEE).CGColor;
    button.layer.borderWidth = ZOOM(1.0);
    [button setTitleColor:WBColorHex(0x999999) forState:UIControlStateNormal];
    return button;
}

- (UIButton *)newDestructiveButton:(WBRichMessageLinkModel *)operation {
    UIButton *button = [self newCommonButton:operation];
    button.layer.borderColor = WBColorHex(0xEEEEEE).CGColor;
    button.layer.borderWidth = ZOOM(1.0);
    [button setTitleColor:WBColorHex(0xff0000) forState:UIControlStateNormal];
    return button;
}

- (UIButton *)newCommonButton:(WBRichMessageLinkModel *)operation {
    UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
    button.layer.cornerRadius = BUTTON_HEIGHT/2;
    button.layer.masksToBounds = YES;
    [button setTitle:operation.label forState:UIControlStateNormal];
    button.titleLabel.font = [UIFont fontWithName:@"PingFang SC" size:ZOOM(14)];
    if (operation.timeout > 0) {
        button.userInteractionEnabled = false;
        button.backgroundColor = WBColorHex(0xEEEEEE);
        [self countDownToEnableButton:button withOperation:operation];
    } else {
        [self enableButton:button withOperation:operation];
    }
    return button;
}

- (void)countDownToEnableButton:(UIButton *)button withOperation:(WBRichMessageLinkModel *)operation {
    if (operation.timeout > 0) {
        NSString *title = [operation.label stringByAppendingFormat:@"  (%d)", operation.timeout];
        [button setTitle:title forState:UIControlStateNormal];
        operation.timeout--;
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [self countDownToEnableButton:button withOperation:operation];
        });
    } else {
        [self enableButton:button withOperation:operation];
    }
}

- (void)enableButton:(UIButton *)button withOperation:(WBRichMessageLinkModel *)operation {
    [button setTitle:operation.label forState:UIControlStateNormal];
    button.userInteractionEnabled = true;
    if (operation.style == WBRichMessageLinkStylePrimary) {
        button.backgroundColor = GreenColor_g;
        [button setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
    } else {
        button.backgroundColor = nil;
    }
}

