- (void)requestReportEventWithType:(WBActionRequestEventType)type defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    if (self.eventActionRequestEnabled) {
        [[WBNetworkManager defaultManager] requestReportEventWithType:type callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
            [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
