- (void)requestReportEventWithType:(WBActionRequestEventType)type data:(NSDictionary *)data defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [self requestReportEventWithType:type data:data defaultHandler:defaultHandler completion:nil];
}

- (void)requestReportEventWithType:(WBActionRequestEventType)type data:(NSDictionary *)data defaultHandler:(WBActionRequestDefaultHandler)defaultHandler completion:(WBActionRequestCompletion)completion {
    if (!self.eventActionRequestEnabled) {
        if (completion) {
            completion(nil);
        }
        return;
    }
    [[WBNetworkManager defaultManager] requestReportEventWithType:type data:data callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
        if (completion) {
            completion(error);
        }
    }];
}


