#import "WBDefaultActionFactory.h"
#import "WBLinkActionModel.h"
#import "WBDefaultActionModel.h"

typedef enum {
    WBActionRequestDataTypeLink = 1,
    WBActionRequestDataTypeDefaultAction = 100,
} WBActionRequestDataType;

@implementation WBDefaultActionFactory

+ (instancetype)sharedFactory {
    static id instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[self alloc] init];
    });
    return instance;
}

- (WBBaseActionModel *)buildActionWithDict:(NSDictionary *)json sourceInterface:(nullable NSString *)sourceInterface {
    WBBaseActionModel *actionModel = nil;

    @try {
        WBActionRequestDataType actionType = [json[@"type"] intValue];
        if(actionType){
            id data = json[@"data"];
            NSParameterAssert(!data || [data isKindOfClass:[NSDictionary class]]);

            // 处理 WBActionRequestDataTypeLink 类型的数据时，需要注入 sourceInterface
            if (actionType == WBActionRequestDataTypeLink) {
                NSMutableDictionary *mutableData = nil;
                if (sourceInterface && [data isKindOfClass:[NSDictionary class]]) {
                    mutableData = [NSMutableDictionary dictionaryWithDictionary:data];
                    [mutableData setObject:sourceInterface forKey:@"sourceInterface"];
                }
                actionModel = [WBLinkActionModel modelWithJSON:(mutableData ?: data)];
            }

            switch (actionType) {
                case WBActionRequestDataTypeLink:
                    actionModel = [WBLinkActionModel modelWithJSON:data];
                    break;
                case WBActionRequestDataTypeDefaultAction:
                    actionModel = [WBDefaultActionModel modelWithJSON:data] ?: [[WBDefaultActionModel alloc] init];
                default:
                    break;
            }
        }else{
