    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    rootVc = rootVc.presentedViewController ?: rootVc;  // 使用当前呈现的视图控制器
    [rootVc addChildViewController:self];
    [rootVc.view addSubview:self.view];
    [self.view layoutSubviews];
    [UIView animateWithDuration:0.01 animations:^{
        self.view.alpha = 1.0;
        self.containerView.transform = CGAffineTransformMakeTranslation(0, -(self.containerView.height - ZOOM(16)));
    }];
    // 显示之后记录下位置，方便后面滑动的移动
    self.originalContainerFrame = self.containerView.frame;
}

