                BOOL hasShared = [WBReferralManager sharedManager].hasShared;
                if (hasShared) {
                    PostNotificationOnMainThread(WBAppShareSuccessNotification, nil);
                    NSLog(@"服务端判定分享成功");
                } else {
                    NSLog(@"服务端判定分享未完成");
                }
            }];
        }];

        if (completed) {
            NSLog(@"客户端回调显示分享完成，分享渠道: %@", activityType);
        } else {
            if (activityType == nil) {
                NSLog(@"用户点击了取消按钮，直接关闭了分享页");
            } else {
                NSLog(@"用户选择了分享渠道 %@，但最终取消了发送", activityType);
