199	        
200	        self.originVC = [WBAppManager getUIApplicationCurrentViewController];    // 获取调用弹窗的原始视图控制器
201	    }
202	    
203	    if (!richMessagesObject) {
204	        // 如果 richMessagesObject 为空，则不进行任何处理
205	        return;
206	    }
207	    // 检查 richMessagesObject 是否为非空数组
208	    if ([richMessagesObject isKindOfClass:[NSArray class]]) {
209	        NSArray *array = (NSArray *)richMessagesObject;
210	        if (array.count == 0 || ([array.firstObject isKindOfClass:[NSDictionary class]] && ((NSDictionary *)[array firstObject]).count == 0)) {
211	            // 如果数组为空或第一个元素是空字典，则不进行任何处理
212	            return;
213	        }
214	    }
215	    
216	    if ([richMessagesObject isKindOfClass:[NSArray class]]) {
217	        // 如果 rich_messages 是数组，遍历并处理每个元素
218	        NSArray *richMessagesArray = richMessagesObject;
219	        if (!self.popupQueue) {
220	            self.popupQueue = [NSMutableArray array];
