229	        
230	        // 显示队列中的第一个弹窗
231	        if ([self.popupQueue count] > 0) {
232	            [self showNextPopupFromQueue:self.popupQueue];
233	        }
234	    } else {
235	        // 如果 rich_message 不是数组，直接处理字典
236	        NSNumber *style = richMessagesObject[@"style"];
