@interface WBReferralManager : NSObject

+ (instancetype)sharedManager;

/// 邀请码
@property (nonatomic, strong) NSNumber *referralCode;

/// 分享奖励时长
@property (nonatomic, strong) NSNumber *shareRewardDuration;

/// 设备邀请人数
@property (nonatomic, strong) NSNumber *inviterCount;

/// 邀请奖励时长
@property (nonatomic, strong) NSNumber *inviterRewardDuration;

/// 初始奖励时长
@property (nonatomic, strong) NSNumber *beginRewardDuration;

/// 账户奖励数
@property (nonatomic, strong) NSNumber *rewardPaymentCount;

/// 填写邀请码奖励
@property (nonatomic, strong) NSNumber *inputRewardDuration;

///是否已经分享
@property (nonatomic, assign) BOOL hasShared;

///是否跳过邀请页
@property (nonatomic, assign) BOOL skipReferralPage;

///活动是否开启
@property (nonatomic, assign) BOOL activityStart;

/// 待执行的路由 URL（用于延迟到主页执行）
@property (nonatomic, strong, nullable) NSURL *pendingRouteURL;

/// 待执行路由的来源接口
@property (nonatomic, strong, nullable) NSString *pendingRouteSourceInterface;

/// 刷新邀请数据
- (void)refreshReferralData;

/// 刷新邀请数据并回调结果
- (void)refreshReferralDataWithCompletion:(void (^ _Nullable)(NSError * _Nullable error))completion;

/// 清空邀请相关数据（用于退出登录后重置 UI 状态）
- (void)resetReferralData;

@end

NS_ASSUME_NONNULL_END

