- (void)viewDidLoad {
    [super viewDidLoad];
    [self setUpUI];
    [self loadDualApps];

    self.navigationItem.rightBarButtonItems = @[self.settingBarButtonItem, self.defaultReadFeedbackBarButtonItem];

    self.loading = kArrayIsEmpty(WBVAppManager.sharedManager.myApps);

    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleMyVAppClick:) name:WBAddPageClickMyVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppGet:) name:WBGetVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppReserve:) name:WBReserveVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppDownloadError:) name:WBVAppDownloadErrorNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppInstallError:) name:WBVAppInstallErrorNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(customPopupDismissed:) name:CustomPopupDismissedNotification object:nil];  // 接收活动弹窗的通知，将 vapp 的启动状态设置为FALSE。
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleReferralDataUpdated) name:WBReferralDataUpdatedNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleAppShareSuccess) name:WBAppShareSuccessNotification object:nil];

    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypePageHomeShow defaultHandler:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handlePopupDismiss) name:WBPopupDismissNotification object:nil];

}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [WBEventManager logAppPageShowEvent:@"Home" from:@""];
    // Nav back from passwordvc or other conditions, which indicates password auth failed or other conditions that cause vapp fail to launch.
    [self handleNewMsgFromFeedbacks];   // 查询最新的客服对话消息

    if (self.isVappLaunching) {
        self.vappLaunching = false; // Reset launch status.
    }

    self.navigationItem.title = nil;
    self.navigationItem.leftBarButtonItem = self.leftTitleBarButtonItem;
    UILabel *label = (UILabel *)self.leftTitleBarButtonItem.customView;
    label.text = self.title ?: NSLocalizedString(@"WhatsBox", nil);
    [label sizeToFit];

}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];

    // Execute pending route after view is fully displayed
    [self checkAndExecutePendingRoute];

    BOOL notFirst = [[NSUserDefaults standardUserDefaults] boolForKey:@"notFirstLaunch"];
    if (!notFirst) {
        [self showIntroMask];
    }
}

- (void)checkAndExecutePendingRoute {
    NSURL *pendingURL = WBReferralManager.sharedManager.pendingRouteURL;
    NSString *sourceInterface = WBReferralManager.sharedManager.pendingRouteSourceInterface;

    if (pendingURL) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBRouteManager sharedManager] performRoute:pendingURL sourceInterface:sourceInterface];

            // Clear after execution
            WBReferralManager.sharedManager.pendingRouteURL = nil;
            WBReferralManager.sharedManager.pendingRouteSourceInterface = nil;
        });
    }
}

- (void)showIntroMask {

    // 防止重复显示
    if ([self.view viewWithTag:9999]) {
        return;
    }

    if (!self.inviteView.superview) {
        return;
    }

    // 确保布局已完成

    [self updateRewardsLabel];
    [self updateInviteLabel];
    [self.inviteView updateUI];
}

- (void)handleAppShareSuccess {
    [self.inviteView updateUI];
}

- (void)updateInviteLabel {
    [self.inviteView setInviteDayCount:WBReferralManager.sharedManager.inviterRewardDuration];
}


- (void)updateRewardsLabel {
    NSInteger reward = [WBReferralManager.sharedManager.inviterRewardDuration integerValue];
    NSInteger beginReward = [WBReferralManager.sharedManager.beginRewardDuration integerValue];
    NSInteger count = [WBReferralManager.sharedManager.rewardPaymentCount integerValue];
    NSInteger inputReward = [WBReferralManager.sharedManager.inputRewardDuration integerValue];
    NSInteger shareReward = [WBReferralManager.sharedManager.shareRewardDuration integerValue];
    NSInteger shareBonus = WBReferralManager.sharedManager.hasShared ? shareReward : 0;
    NSInteger totalReward;
    if (kStringIsEmpty(WBSettingManager.sharedManager.Email) || !WBReferralManager.sharedManager.activityStart) {
        totalReward = 0;
    } else {
        totalReward = beginReward + inputReward + reward * count + shareBonus;
    }
    [self.inviteView setTotalRewardDays:totalReward];
}

}

- (void)handleShare {
    [[WBAppManager sharedManager] shareAppByIOSShare];
    [WBEventManager logReferralActivitywithCode:@"shareCode"];
}

- (void)handleCopy {
    [UIPasteboard generalPasteboard].string = self.codeLabel.text;
    [SVProgressHUD showSuccessWithStatus:NSLocalizedString(@"已复制到粘贴板", nil)];
    [WBEventManager logReferralActivitywithCode:@"copy"];
}


#pragma mark - Private Helpers

- (void)setupNavigationItems {
    UIBarButtonItem *rightItem = [[UIBarButtonItem alloc] initWithCustomView:self.customButton];
    self.navigationItem.rightBarButtonItem = rightItem;
}

- (void)setupNotifications {
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleReferralDataUpdated) name:WBReferralDataUpdatedNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleAppShareSuccess) name:WBAppShareSuccessNotification object:nil];
}

- (BOOL)hasEnteredInvitePageBefore {
    return [[NSUserDefaults standardUserDefaults] boolForKey:kWBNotFirstEnterInvitePageKey];
}

- (void)markInvitePageEntered {
    [[NSUserDefaults standardUserDefaults] setBool:YES forKey:kWBNotFirstEnterInvitePageKey];
}

- (UIView *)buildIntroMaskForButton:(UIButton *)button {
    CGRect buttonFrame = [self.view convertRect:button.bounds fromView:button];
    UIView *mask = [[UIView alloc] init];
    mask.tag = kWBInviteIntroMaskTag;
    mask.backgroundColor = [UIColor clearColor];
    mask.frame = self.view.bounds;
    [self.view addSubview:mask];

    [_rulesContentLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.rulesContentView);
        make.top.equalTo(self.rulesTitleLabel.mas_bottom).offset(ZOOM(12));
        make.bottom.equalTo(self.rulesContentView);
    }];
}

