+ (instancetype)sharedManager {
    static WBReferralManager *manager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        manager = [[self alloc] init];
    });
    return manager;
}

- (void)applyReferralDataWithJSON:(NSDictionary *)json {
    self.referralCode = json[@"referralCode"];
    self.shareRewardDuration = json[@"shareRewardDuration"];
    self.inviterCount = json[@"inviterCount"];
    self.inviterRewardDuration = json[@"inviterRewardDuration"];
    self.beginRewardDuration = json[@"initRewardDuration"];
    self.rewardPaymentCount = json[@"rewardPaymentCount"];
    self.inputRewardDuration = json[@"inputRewardDuration"];
    self.hasShared = [json[@"hasShared"] boolValue];
    self.skipReferralPage = [json[@"skipReferralPage"] boolValue];
    self.activityStart = [json[@"activityStart"] boolValue];
}

- (void)refreshReferralData {
    [self refreshReferralDataWithCompletion:nil];
}

- (void)refreshReferralDataWithCompletion:(void (^ _Nullable)(NSError * _Nullable error))completion {
    [[WBNetworkManager defaultManager] getReferralInitcallback:^(id  _Nullable json, NSError * _Nullable error) {
        if (error) {
            NSLog(@"Failed to refresh referral data: %@", error);
            if (completion) {
                completion(error);
            }
            return;
        }

        NSParameterAssert([json isKindOfClass:[NSDictionary class]]);
        if (![json isKindOfClass:[NSDictionary class]]) {
            NSError *invalidResponseError = [NSError errorWithDomain:@"WBReferralManager"
                                                                code:-1
                                                            userInfo:@{NSLocalizedDescriptionKey: @"Invalid referral init response."}];
            if (completion) {
                completion(invalidResponseError);
            }
            return;
        }

        [self applyReferralDataWithJSON:json];

        PostNotificationOnMainThread(WBReferralDataUpdatedNotification, nil);
        if (completion) {
            completion(nil);
        }
    }];
}

- (void)resetReferralData {
    self.referralCode = @(0);
    self.inviterCount = @(0);
    self.inviterRewardDuration = @(0);
    self.beginRewardDuration = @(0);
    self.rewardPaymentCount = @(0);
    self.inputRewardDuration = @(0);
    self.hasShared = NO;
    self.skipReferralPage = NO;
    self.activityStart = NO;
    self.pendingRouteURL = nil;
    self.pendingRouteSourceInterface = nil;
}

@end

