@interface WBSettingManager()

@property(nonatomic, strong) NSUserDefaults *userDefaults;

@end

@implementation WBSettingManager

#pragma mark singleton & init

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBSettingManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    self.userDefaults = [NSUserDefaults standardUserDefaults];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleShareLinkNotification:) name:WBPresentShareUrlNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(backToOriginalShareInfoNotification) name:WBBackToOriginalShareUrlNotification object:nil];
    return self;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)handleShareLinkNotification:(NSNotification *)notification {
    // 从通知中获取 userInfo 字典
    NSDictionary *shareLinkInfo = [notification userInfo];
    NSString *shareLink = [shareLinkInfo objectForKey:@"shareUrl"];
    if(shareLink) {
        self.ShareURL = shareLink;
    } else {
        // 使用user/token里面的默认分享链接
    }
}

// 分享完当前打开的网页之后，重置为默认分享网页（分享落地页）
- (void)backToOriginalShareInfoNotification {
    self.ShareURL = self.originalShareUrl;
}

- (BOOL)EnableADS {
    return [self isAdsAppIdValid:self.ADSAppId];
}

- (BOOL)isAdsAppIdValid:(NSString *)adsAppId {
    return adsAppId.length && [adsAppId integerValue] != 0;
}

- (void)syncWithUserInfo:(WBUserInfoHttpModel *)userInfo {
    self.IsVIP = userInfo.is_vip;
    self.IsGuest = userInfo.is_guest;
    self.IsTrial = userInfo.is_trial;
    self.HasPassword = userInfo.has_password;
    self.Email = userInfo.email;
    self.VIPExpires = [WBUtility convertUTC2Local:userInfo.vip_expires];
    self.VIPExpires = [self.VIPExpires substringToIndex:10];
    self.HideExpirationAlert = !userInfo.expirationAlert;
}

- (void)syncWithAppVersionInfo:(WBAppVersionInfoHttpModel *)appVersionInfo {
    self.HasUpdate = appVersionInfo.has_update;
    self.RemindUpdate = appVersionInfo.remind_update;
    self.ForceUpdate = appVersionInfo.force_update;
    self.TrackId = appVersionInfo.track_id;
    self.UpdateDescription = appVersionInfo.desc;
}

- (void)syncWithHeatBeatResponse:(WBHeartBeatHttpModel *)heartBeat {
    self.HasNewNotice = heartBeat.new_sys_msg;
    self.HasNewMessage = heartBeat.new_css_msg;
    self.HasNewPromo = heartBeat.new_promocode;
    if (self.IsTrial && heartBeat.trial_over) {
        self.IsTrial = FALSE;
    }
    if (self.IsVIP && heartBeat.vip_expired) {
        self.IsVIP = FALSE;
    }
#ifdef VIP
    self.IsVIP = true;
    self.IsTrial = false;
#endif
    if (heartBeat.log_rate) {
        self.LogRate = heartBeat.log_rate;
    }
    if (heartBeat.hb_rate) {
        self.HeartBeatRate = heartBeat.hb_rate;
    }
    PostNotificationOnMainThread(WBUserMsgStatusUpdateNotification, nil);
}

- (void)syncWithCompatibles:(WBCompatibleHttpModel *)compatibles {
    self.DyldSect = compatibles.dysect;
    self.DyldOffset = compatibles.dyos;
}

- (void)syncWithStrings:(WBStringsHttpModel *)strings {
    self.TrialOverMsg = strings.trial_over_msg;
    self.TrialRemindMsg = strings.trial_remind_msg;
}

- (void)syncWithUrls:(WBUrlsHttpModel *)urls {
    self.PrivacyURL = urls.privacy;
    self.UserTermURL = urls.agreement;
    self.ShareURL = urls.share;
    self.originalShareUrl = urls.share;
}

- (void)syncWithTip:(WBHomeTipHttpModel *)tip {
    self.TipImageUrl = tip.imageUrl;
    self.TipTapLinkType = tip.tapLinkType;
    self.TipTapLink = tip.tapLink;
}

- (void)syncWithConfigs:(WBConfigsHttpModel *)configs {
    self.HeartBeatRate = configs.hb_rate;
    self.LogRate = configs.log_rate;

    self.HideExpirationAlert = !configs.expirationAlert;
}


- (BOOL)getSkipGuideForFeature:(NSString*)featureName {
    return [self getBool:featureName];
}

- (void)setSkipGuideForFeature:(NSString*)featureName {
    [self setBool:TRUE forKey:featureName];
}


#pragma mark private

- (void)setObject:(id)obj forKey:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    [self.userDefaults setObject:obj forKey:hashedKey];
//    NSLog(@"WBSettingManager: setObject:%@ forKey:%@ hashedKey:%@", obj, key, hashedKey);
}

- (void)setInteger:(NSInteger)val forKey:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    [self.userDefaults setInteger:val forKey:hashedKey];
//    NSLog(@"WBSettingManager: setInteger:%zd forKey:%@ hashedKey:%@", val, key, hashedKey);
}

- (void)setBool:(BOOL)val forKey:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    [self.userDefaults setBool:val forKey:hashedKey];
//    NSLog(@"WBSettingManager: setBool:%d forKey:%@ hashedKey:%@", val, key, hashedKey);
}


- (NSInteger)getInteger:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    NSInteger val = [self.userDefaults integerForKey:hashedKey];
//    NSLog(@"WBSettingManager: getInteger:%zd forKey:%@ hashedKey:%@", val, key, hashedKey);
    return val;
}

- (NSString *)getStringValue:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    NSString *val = [self.userDefaults stringForKey:hashedKey];
//    NSLog(@"WBSettingManager: getString:%@ forKey:%@ hashedKey:%@", val, key, hashedKey);
    return val;
}

- (BOOL)getBool:(NSString *)key {
    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    BOOL val = [self.userDefaults boolForKey:hashedKey];
//    NSLog(@"WBSettingManager: getBool:%d forKey:%@ hashedKey:%@", val, key, hashedKey);
    return val;
}


