        if (error) {
            NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
        } else {
            // 刷新邀请数据
            [[WBReferralManager sharedManager] refreshReferralData];
            if (json && ![json isKindOfClass:[NSNull class]]) {

                if (self.isInApp) {
                    [WBEventManager logReferralActivitywithCode:@"confirmB"];
                }else {
                    [WBEventManager logReferralActivitywithCode:@"confirmA"];
                }
                [WBEventManager flushEvents];
                WBUserInfoHttpModel *model = [WBUserInfoHttpModel modelWithJSON:json[@"vipInfoVo"]];
                [WBSettingManager.sharedManager syncWithUserInfo:model];
                // 如果有路由，在dismiss后执行
                if (json && [json[@"route"][@"type"] integerValue] == 1) {
                    NSDictionary *routeData = json[@"route"][@"data"];
                    NSString *link = routeData[@"link"];
                    NSURL *url = [NSURL URLWithString:link];
                    if (url) {
