                            [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"referral/register"];
                        });
                    }
                }
            } else {
                [SVProgressHUD showInfoWithStatus:@"活动未开启"];
            }
        }
        PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
    }];
