- (void)reachabilityChanged:(NSNotification *)noti {
    Reachability *curReach = [noti object];
    if(FALSE == [curReach isKindOfClass:[Reachability class]]) {// 确保通知中的对象是 Reachability 类型。
        return;
    }

    NetworkStatus netStatus = [curReach currentReachabilityStatus];// 获取当前的网络状态。
    [WBEventManager logAppNetworkConnectEvent:[@(netStatus) stringValue]];

    if (netStatus == NotReachable) {// 如果网络不可达，当前不做任何处理，但提供了一个 TODO 以提示后续可能的实现
        // no network, do nothing
        // TODO: guide to system settings?
    } else {// 如果网络可达，在异步队列上执行以下操作。
        dispatch_async([self queue], ^{
            [self requestTokenFromServer];// 请求从服务器获取新的令牌。
        });
    }
}

- (void)requestTokenFromServer {

    if (_tokenRefreshStatus != tokenAwaitRefresh) {// 检查当前的令牌刷新状态是否为等待刷新（tokenAwaitRefresh），如果不是则直接返回。
        return;
    }
    // 检查是否满足再次请求的条件：WBQuery 初始化成功且当前时间距离上次请求时间超过设定的请求间隔。
    if (([[WBQuery query] tryInit] == FALSE) || (CFAbsoluteTimeGetCurrent() < _lastRequestTime+_requestInterval)) {
        // 如果不满足条件，则在主队列上延迟0.1秒后再次尝试请求令牌。
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1*NSEC_PER_SEC)), [self queue], ^{
            [self requestTokenFromServer];
        });
        return;
    }
    _tokenRefreshStatus = tokenRefreshing;// 将令牌刷新状态更新为正在刷新（tokenRefreshing）。

    [WBEventManager logAppTokenRefreshEvent];// 记录应用程序的令牌刷新事件。
    // 异步请求从服务器刷新令牌，并通过回调处理响应结果。
    [[WBNetworkManager defaultManager] refreshToken:^(NSDictionary *json, NSError * _Nullable error) {
        // the callback operation might be time consuming, run it on a none main thread
        dispatch_async([self queue], ^{// 异步处理回调操作，因为这些操作可能比较耗时。
            if (json) {
                self.tokenRefreshStatus = tokenRefreshed;// 请求成功，更新令牌刷新状态为已刷新（tokenRefreshed）。
                NSLog(@"%@", json);// 打印响应的 JSON 数据以供调试。
                [WBSettingManager.sharedManager syncWithUserInfo:[WBUserInfoHttpModel modelWithJSON:json]];// 使用响应的 JSON 数据同步用户信息。
                WBSettingManager.sharedManager.Token = [json objectForKey:@"token"];// 更新全局的令牌。
                [WBPlugManager.sharedManager appDidRequestToken:json];// 通知插件管理器应用程序已请求令牌。
                if ([json objectForKey:@"cr"]) {// 如果响应中包含崩溃报告（cr）字段，则初始化崩溃报告路径并上传现有的崩溃日志。
                    // crash report path init, upload existing crash report
                    oaa_set_plc_report_path(WBStorageManager.sharedManager.crashReportFilePath);
                    [self uploadCrashLogs];

                    // parse the rest of the response

                    [WBEventManager logAppTokenRefreshResultEvent:@"2"];// 记录应用程序的令牌刷新结果事件。

                    // 处理初始化逻辑，包括本地化、字符串、URL、版本信息、配置、弹出通知、VIP特性等。
                    // deal with engine resource
                    //
                    if ([WBEngresManager.sharedManager initWithEngres:[WBLocalizeHttpModel modelWithJSON:json[@"config"][@"localize"]]] == FALSE) {
                        // TODO: show init fail msg
                        return;
                    }
                    //
                    // deal with compatible settings
                    //
                    [WBSettingManager.sharedManager syncWithCompatibles:[WBCompatibleHttpModel modelWithJSON:json[@"config"][@"compatible"]]];
                    //
                    // deal with strings
                    [WBSettingManager.sharedManager syncWithStrings:[WBStringsHttpModel modelWithJSON:json[@"config"][@"strings"]]];
                    //
                    // deal with urls
                    [WBSettingManager.sharedManager syncWithUrls:[WBUrlsHttpModel modelWithJSON:json[@"config"][@"urls"]]];

