        [self addAllSubviews];
        [self addAllConstraints];
    }
    return self;
}


#pragma mark - Setup UI

- (void)addAllSubviews {
    [self addSubview:self.containerView];
    [self.containerView addSubview:self.toInviteLabel];
    [self.containerView addSubview:self.toInviteImageView];
    [self.containerView addSubview:self.toInvitePageButton];
    [self.toInvitePageButton addSubview:self.durationRewardLabel];
    [self.containerView addSubview:self.shareButton];
}

- (void)addAllConstraints {
    [_containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self);
    }];

    [_toInviteImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(self.containerView).offset(ZOOM(2));
        } else {
            make.right.equalTo(self.containerView).offset(ZOOM(-2));
        }
        make.bottom.equalTo(self.containerView).offset(ZOOM(-12));
        make.width.height.mas_equalTo(ZOOM(24));
    }];

    [_toInviteLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        if ([WBAppManager sharedManager].isRTL) {
            make.left.equalTo(self.toInviteImageView.mas_right).offset(ZOOM(3));
        } else {
            make.right.equalTo(self.toInviteImageView.mas_left).offset(ZOOM(-3));
        }
        make.centerY.equalTo(self.toInviteImageView);
    }];

    [_toInvitePageButton mas_makeConstraints:^(MASConstraintMaker *make) {
        if (WBReferralManager.sharedManager.hasShared) {
            make.left.right.equalTo(self.containerView).inset(ZOOM(-6));
            make.top.equalTo(self.containerView).offset(ZOOM(-4));
            make.height.mas_equalTo(ZOOM(98));
        } else {
            make.top.left.right.equalTo(self.containerView);
            make.height.mas_equalTo(ZOOM(80));
        }
    }];

    [_durationRewardLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(self.toInvitePageButton);
    }];

    [_shareButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.containerView);
    }];
}


#pragma mark - Events

- (void)handleTap {
    if (self.onTapInvite) self.onTapInvite();
}

- (void)handleShare {
    if (kStringIsEmpty(WBSettingManager.sharedManager.Email)) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"请先登录", nil)
                                                                       message:NSLocalizedString(@"登录后可参与分享活动并获得奖励。", nil)
                                                                preferredStyle:UIAlertControllerStyleAlert];
        UIAlertAction *cancel = [UIAlertAction actionWithTitle:NSLocalizedString(@"取消", nil)
                                                         style:UIAlertActionStyleDefault
                                                       handler:nil];
        UIAlertAction *login = [UIAlertAction actionWithTitle:NSLocalizedString(@"登录", nil)
                                                        style:UIAlertActionStyleDefault
                                                      handler:^(UIAlertAction * _Nonnull action) {
            WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
            loginVC.loginSource = WBLoginSourceInvite;
            UINavigationController *loginNav = [[UINavigationController alloc] initWithRootViewController:loginVC];
            loginNav.modalPresentationStyle = UIModalPresentationFullScreen;
            UIViewController *currentVC = [WBAppManager getUIApplicationCurrentViewController];
            [currentVC presentViewController:loginNav animated:YES completion:nil];
        }];
        [alert addAction:cancel];
        [alert addAction:login];
        UIViewController *currentVC = [WBAppManager getUIApplicationCurrentViewController];
        [currentVC presentViewController:alert animated:YES completion:nil];
        return;
    }
    [[WBAppManager sharedManager] shareAppByIOSShare];
    [WBEventManager logReferralActivitywithCode:@"shareMainPage"];
}


#pragma mark - Public APIs

- (void)setInviteDayCount:(NSNumber *)dayCount {
    self.inviteDayCountNumber = dayCount;
    NSInteger userCount = 1;
    NSString *prefix = NSLocalizedString(@"邀请", nil);
    NSString *middle = NSLocalizedString(@"位用户", nil);
    NSString *suffix = NSLocalizedString(@"天", nil);
    NSString *userStr = [NSString stringWithFormat:@" %ld ", (long)userCount];
    NSString *dayStr = [NSString stringWithFormat:@" + %@ ", dayCount];
    NSMutableAttributedString *attrStr = [[NSMutableAttributedString alloc] init];
    UIColor *textColor = WBColorHex(0x24CF41);
    UIFont *smallFont = [UIFont systemFontOfSize:ZOOM(18) weight:UIFontWeightMedium];
    UIFont *largeFont = [UIFont systemFontOfSize:ZOOM(24) weight:UIFontWeightMedium];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:prefix attributes:@{NSFontAttributeName: smallFont, NSForegroundColorAttributeName: textColor}]];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:userStr attributes:@{NSFontAttributeName: largeFont, NSForegroundColorAttributeName: textColor}]];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:middle attributes:@{NSFontAttributeName: smallFont, NSForegroundColorAttributeName: textColor}]];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:dayStr attributes:@{NSFontAttributeName: largeFont, NSForegroundColorAttributeName: textColor}]];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:suffix attributes:@{NSFontAttributeName: smallFont, NSForegroundColorAttributeName: textColor}]];
    self.toInviteLabel.attributedText = attrStr;
    self.toInviteLabel.textAlignment = NSTextAlignmentNatural;
