}

- (void)setTotalRewardDays:(NSInteger)days {
    self.currentTotalRewardDays = days;
    NSString *rewardText = [NSString stringWithFormat:@"%ld", (long)days];
    NSString *suffix = NSLocalizedString(@"天", nil);
    NSMutableAttributedString *attrStr = [[NSMutableAttributedString alloc] init];
    UIColor *textColor = WBReferralManager.sharedManager.hasShared ? WBColorHex(0xFFFFFF) : WBColorHex(0x24CF41);
    UIFont *smallFont = [UIFont systemFontOfSize:ZOOM(18) weight:UIFontWeightMedium];
    UIFont *largeFont = [UIFont systemFontOfSize:ZOOM(58) weight:UIFontWeightMedium];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:rewardText attributes:@{NSFontAttributeName: largeFont, NSForegroundColorAttributeName: textColor}]];
    [attrStr appendAttributedString:[[NSAttributedString alloc] initWithString:suffix attributes:@{NSFontAttributeName: smallFont, NSForegroundColorAttributeName: textColor}]];
    self.durationRewardLabel.attributedText = attrStr;
}

- (void)updateUI {
    BOOL completed = WBReferralManager.sharedManager.hasShared;
    self.containerView.backgroundColor = completed ? WBColorHex(0xEAF9ED) : [UIColor clearColor];
    self.toInviteLabel.hidden = !completed;
    self.toInviteImageView.hidden = !completed;
    self.shareButton.hidden = completed;
    [self updateShareButtonTitle];
    NSString *durationImageName = nil;
    if (completed) {
        durationImageName = [WBAppManager sharedManager].isRTL ? @"Home_duration_backImage_shared_RTL" : @"Home_duration_backImage_shared";
    } else {
        durationImageName = [WBAppManager sharedManager].isRTL ? @"Home_duration_backImage_RTL" : @"Home_duration_backImage";
    }
    [self.toInvitePageButton setBackgroundImage:[UIImage imageNamed:durationImageName] forState:UIControlStateNormal];
    [_toInvitePageButton mas_remakeConstraints:^(MASConstraintMaker *make) {
        if (WBReferralManager.sharedManager.hasShared) {
            make.left.right.equalTo(self.containerView).inset(ZOOM(-6));
            make.top.equalTo(self.containerView).offset(ZOOM(-4));
            make.height.mas_equalTo(ZOOM(98));
        } else {
            make.top.left.right.equalTo(self.containerView);
            make.height.mas_equalTo(ZOOM(80));
        }
    }];

    [self setInviteDayCount:self.inviteDayCountNumber ?: @(0)];
    [self setTotalRewardDays:self.currentTotalRewardDays];
}

- (void)updateShareButtonTitle {
    NSInteger shareRewardDuration = [WBReferralManager.sharedManager.shareRewardDuration integerValue];
    NSString *rewardText = [NSString stringWithFormat:@"%ld", (long)shareRewardDuration];
    NSMutableAttributedString *attrTitle = [[NSMutableAttributedString alloc] init];
    UIColor *textColor = [UIColor whiteColor];
    UIFont *plusFont = [UIFont systemFontOfSize:ZOOM(24) weight:UIFontWeightMedium];
    UIFont *numberFont = [UIFont systemFontOfSize:ZOOM(36) weight:UIFontWeightMedium];
    NSAttributedString *plusAttr = [[NSAttributedString alloc] initWithString:@"+"
                                                                    attributes:@{NSFontAttributeName: plusFont,
                                                                                 NSForegroundColorAttributeName: textColor}];
    NSAttributedString *numberAttr = [[NSAttributedString alloc] initWithString:rewardText
                                                                      attributes:@{NSFontAttributeName: numberFont,
                                                                                   NSForegroundColorAttributeName: textColor}];
    if ([WBAppManager sharedManager].isRTL) {
        [attrTitle appendAttributedString:numberAttr];
        [attrTitle appendAttributedString:plusAttr];
    } else {
        [attrTitle appendAttributedString:plusAttr];
        [attrTitle appendAttributedString:numberAttr];
    }
    [self.shareButton setAttributedTitle:attrTitle forState:UIControlStateNormal];
}

